  // Identificar origem
  if (mensagemLower.includes("anúncio do meta") || mensagemLower.includes("no instagram") || mensagemLower.includes("facebook")) {
    lead_origem = "meta";
  } else if (mensagemLower.includes("google") || mensagemLower.includes("em um anúncio")) {
    lead_origem = "google";
  } else {
    lead_origem = "organico";
  }

} else {
  // Não é mensagem de lead - cliente orgânico, loja padrão
